import{_ as a,c as i,o as e,a1 as s}from"./chunks/framework.DILC4Csi.js";const k=JSON.parse('{"title":"Быстрый старт: Начало работы с OpenSkills | OpenSkills","description":"Изучите быстрый старт с OpenSkills. За 15 минут установите инструменты и навыки, чтобы ИИ-агенты могли использовать новые возможности и понимать принципы работы.","frontmatter":{"title":"Быстрый старт: Начало работы с OpenSkills | OpenSkills","sidebarTitle":"15 минут до старта","subtitle":"Быстрый старт: Начало работы с OpenSkills | OpenSkills","description":"Изучите быстрый старт с OpenSkills. За 15 минут установите инструменты и навыки, чтобы ИИ-агенты могли использовать новые возможности и понимать принципы работы.","order":1},"headers":[],"relativePath":"ru/numman-ali/openskills/start/index.md","filePath":"ru/numman-ali/openskills/start/index.md"}'),t={name:"ru/numman-ali/openskills/start/index.md"};function n(r,l,o,h,d,p){return e(),i("div",null,[...l[0]||(l[0]=[s(`<h1 id="быстрыи-старт" tabindex="-1">Быстрый старт <a class="header-anchor" href="#быстрыи-старт" aria-label="Permalink to &quot;Быстрый старт&quot;">​</a></h1><p>Этот раздел поможет вам быстро освоить OpenSkills — от установки инструментов до использования навыков ИИ-агентом всего за 10-15 минут.</p><h2 id="путь-обучения" tabindex="-1">Путь обучения <a class="header-anchor" href="#путь-обучения" aria-label="Permalink to &quot;Путь обучения&quot;">​</a></h2><p>Рекомендуем изучать материал в следующем порядке:</p><h3 id="_1-быстрыи-старт" tabindex="-1">1. <a href="./quick-start/">Быстрый старт</a> <a class="header-anchor" href="#_1-быстрыи-старт" aria-label="Permalink to &quot;1. [Быстрый старт](./quick-start/)&quot;">​</a></h3><p>За 5 минут установите инструменты, навыки и выполните синхронизацию, чтобы оценить ключевые возможности OpenSkills.</p><ul><li>Установка инструментов OpenSkills</li><li>Установка навыков из официального репозитория Anthropic</li><li>Синхронизация навыков в AGENTS.md</li><li>Проверка доступности навыков для ИИ-агента</li></ul><h3 id="_2-что-такое-openskills" tabindex="-1">2. <a href="./what-is-openskills/">Что такое OpenSkills?</a> <a class="header-anchor" href="#_2-что-такое-openskills" aria-label="Permalink to &quot;2. [Что такое OpenSkills?](./what-is-openskills/)&quot;">​</a></h3><p>Понимание основных концепций и принципов работы OpenSkills.</p><ul><li>Связь OpenSkills с Claude Code</li><li>Единый формат навыков, постепенная загрузка, поддержка нескольких агентов</li><li>Когда использовать OpenSkills вместо встроенной системы навыков</li></ul><h3 id="_3-руководство-по-установке" tabindex="-1">3. <a href="./installation/">Руководство по установке</a> <a class="header-anchor" href="#_3-руководство-по-установке" aria-label="Permalink to &quot;3. [Руководство по установке](./installation/)&quot;">​</a></h3><p>Подробные инструкции по установке и настройке окружения.</p><ul><li>Проверка окружения Node.js и Git</li><li>Временное использование через npx vs глобальная установка</li><li>Устранение типичных проблем при установке</li></ul><h3 id="_4-установка-первого-навыка" tabindex="-1">4. <a href="./first-skill/">Установка первого навыка</a> <a class="header-anchor" href="#_4-установка-первого-навыка" aria-label="Permalink to &quot;4. [Установка первого навыка](./first-skill/)&quot;">​</a></h3><p>Установка навыка из официального репозитория Anthropic с интерактивным выбором.</p><ul><li>Использование команды <code>openskills install</code></li><li>Интерактивный выбор нужных навыков</li><li>Понимание структуры каталога навыков (.claude/skills/)</li></ul><h3 id="_5-синхронизация-навыков-в-agents-md" tabindex="-1">5. <a href="./sync-to-agents/">Синхронизация навыков в AGENTS.md</a> <a class="header-anchor" href="#_5-синхронизация-навыков-в-agents-md" aria-label="Permalink to &quot;5. [Синхронизация навыков в AGENTS.md](./sync-to-agents/)&quot;">​</a></h3><p>Генерация файла AGENTS.md, чтобы ИИ-агент знал о доступных навыках.</p><ul><li>Использование команды <code>openskills sync</code></li><li>Понимание XML-формата AGENTS.md</li><li>Выбор навыков для синхронизации, управление размером контекста</li></ul><h3 id="_6-использование-навыков" tabindex="-1">6. <a href="./read-skills/">Использование навыков</a> <a class="header-anchor" href="#_6-использование-навыков" aria-label="Permalink to &quot;6. [Использование навыков](./read-skills/)&quot;">​</a></h3><p>Узнайте, как ИИ-агент загружает содержимое навыков.</p><ul><li>Использование команды <code>openskills read</code></li><li>4 уровня приоритета поиска навыков</li><li>Чтение нескольких навыков одновременно</li></ul><h2 id="предварительные-требования" tabindex="-1">Предварительные требования <a class="header-anchor" href="#предварительные-требования" aria-label="Permalink to &quot;Предварительные требования&quot;">​</a></h2><p>Перед началом обучения убедитесь, что:</p><ul><li>Установлен <a href="https://nodejs.org/" target="_blank" rel="noreferrer">Node.js</a> версии 20.6.0 или выше</li><li>Установлен <a href="https://git-scm.com/" target="_blank" rel="noreferrer">Git</a> (для установки навыков с GitHub)</li><li>Установлен хотя бы один ИИ-агент для программирования (Claude Code, Cursor, Windsurf, Aider и др.)</li></ul><div class="tip custom-block"><p class="custom-block-title">Быстрая проверка окружения</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">node</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # Должно отобразиться v20.6.0 или выше</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # Должно отобразиться git version x.x.x</span></span></code></pre></div></div><h2 id="следующие-шаги" tabindex="-1">Следующие шаги <a class="header-anchor" href="#следующие-шаги" aria-label="Permalink to &quot;Следующие шаги&quot;">​</a></h2><p>После завершения этого раздела можно продолжить изучение:</p><ul><li><a href="./../platforms/cli-commands/">Подробное описание команд</a>: Глубокое изучение всех команд и параметров</li><li><a href="./../platforms/install-sources/">Источники установки</a>: Установка навыков с GitHub, из локальных путей, приватных репозиториев</li><li><a href="./../advanced/create-skills/">Создание собственных навыков</a>: Разработка ваших собственных навыков</li></ul>`,29)])])}const u=a(t,[["render",n]]);export{k as __pageData,u as default};
